simple_types.code:
type Value is delta V_Delta range -V_Range .. V_Range - V_Delta
  with Size  => Integer_Bits + Fractional_Bits,
       Small => V_Delta;

record_types.code:
type Circle is record
   Org    : Point;
   Radius : Value;
end record;

type Rectangle is record
   Org    : Point;
   Width  : Value;
   Height : Value;
end record;

type Vect is record
   X, Y : Value;
end record;
